-        // Skip comments and empty lines
-        const trimmed = std.mem.trim(u8, line, " \t\r");
-        if (trimmed.len == 0 or trimmed[0] == '#') continue;
-
-        // Find = separator
-        const eq_pos = std.mem.indexOfScalar(u8, trimmed, '=') orelse continue;
